fixed_code:
fn main() {
    struct Person { name: String }

    let people = vec![Person { name: "Alice".to_string() }];

    for p in people.iter() {
        let _ = p.name;
    }

    // Use get to avoid out of bounds access
    if let Some(first) = people.get(0) {
        println!("{}", first.name);
    }
}
